('ar', 'ipo-preparation', '{"ipo_preparation":{"hero":{"title":"حلول","title_highlight":"التحضير للاكتتاب العام","description":"تنقل في طريقك إلى الأسواق العامة بثقة.","cta_button_text":"ابدأ تقييم الاكتتاب","cta_button_link":"https://calendly.com/amplifix/amplifix-discovery"},"ipo_process":{"title":"منصة جاهزية الاكتتاب الكاملة","features":[{"title":"إعداد S-1","description":"إعداد بيان التسجيل بمساعدة AI.","icon":"FileText"},{"title":"جاهزية الامتثال","description":"إعداد امتثال SOX الشامل.","icon":"Shield"},{"title":"دعم الجولة الترويجية","description":"تحسين عرض المستثمرين.","icon":"Users"},{"title":"إدارة الجدول الزمني","description":"إدارة مشروع مفصلة.","icon":"Clock"},{"title":"تحديد المواقع في السوق","description":"تطوير السرد الاستراتيجي.","icon":"TrendingUp"},{"title":"الانتقال بعد الاكتتاب","description":"انتقال سلس إلى عمليات الشركة العامة.","icon":"CheckCircle"}]},"checklist":{"title":"قائمة تحقق جاهزية الاكتتاب","sections":[{"section_title":"الإعداد المالي والقانوني","items":["بيانات مالية مدققة (3 سنوات)","تنفيذ امتثال SOX","هيكل حوكمة الشركات","تحسين تكوين مجلس الإدارة"]},{"section_title":"الاتصالات وعلاقات المستثمرين","items":["تطوير أطروحة الاستثمار","مواد عرض الإدارة","موقع ومواد علاقات المستثمرين","استراتيجية الإعلام والمحللين"]}]}}}'),
('ro', 'ipo-preparation', '{"ipo_preparation":{"hero":{"title":"Soluții","title_highlight":"Pregătire IPO","description":"Navighează cu încredere spre piețele publice.","cta_button_text":"Începe Evaluarea IPO","cta_button_link":"https://calendly.com/amplifix/amplifix-discovery"},"ipo_process":{"title":"Platformă Completă de Pregătire IPO","features":[{"title":"Pregătire S-1","description":"Pregătire asistată de AI.","icon":"FileText"},{"title":"Pregătire Conformitate","description":"Pregătire completă SOX.","icon":"Shield"},{"title":"Suport Roadshow","description":"Optimizare prezentări investitori.","icon":"Users"},{"title":"Management Timeline","description":"Management de proiect detaliat.","icon":"Clock"},{"title":"Poziționare Piață","description":"Dezvoltare narativ strategic.","icon":"TrendingUp"},{"title":"Tranziție Post-IPO","description":"Tranziție lină la operațiuni publice.","icon":"CheckCircle"}]},"checklist":{"title":"Checklist Pregătire IPO","sections":[{"section_title":"Pregătire Financiară și Legală","items":["Situații financiare auditate (3 ani)","Implementare conformitate SOX","Structură guvernanță corporativă","Optimizare compoziție consiliu"]},{"section_title":"Comunicații și IR","items":["Dezvoltare teză investiție","Materiale prezentare management","Website și materiale IR","Strategie media și analiști"]}]}}}'),
('th', 'ipo-preparation', '{"ipo_preparation":{"hero":{"title":"โซลูชัน","title_highlight":"การเตรียม IPO","description":"นำทางสู่ตลาดสาธารณะด้วยความมั่นใจ","cta_button_text":"เริ่มการประเมิน IPO","cta_button_link":"https://calendly.com/amplifix/amplifix-discovery"},"ipo_process":{"title":"แพลตฟอร์มความพร้อม IPO ครบวงจร","features":[{"title":"การเตรียม S-1","description":"การเตรียมด้วยความช่วยเหลือของ AI","icon":"FileText"},{"title":"ความพร้อมด้านการปฏิบัติตาม","description":"การเตรียมการ SOX อย่างครอบคลุม","icon":"Shield"},{"title":"การสนับสนุน Roadshow","description":"การเพิ่มประสิทธิภาพการนำเสนอ","icon":"Users"},{"title":"การจัดการไทม์ไลน์","description":"การจัดการโปรเจกต์โดยละเอียด","icon":"Clock"},{"title":"การวางตำแหน่งตลาด","description":"การพัฒนาเรื่องราวเชิงกลยุทธ์","icon":"TrendingUp"},{"title":"การเปลี่ยนผ่านหลัง IPO","description":"การเปลี่ยนผ่านอย่างราบรื่น","icon":"CheckCircle"}]},"checklist":{"title":"รายการตรวจสอบความพร้อม IPO","sections":[{"section_title":"การเตรียมการทางการเงินและกฎหมาย","items":["งบการเงินที่ตรวจสอบแล้ว (3 ปี)","การดำเนินการตาม SOX","โครงสร้างธรรมาภิบาลองค์กร","การเพิ่มประสิทธิภาพองค์ประกอบคณะกรรมการ"]},{"section_title":"การสื่อสารและ IR","items":["การพัฒนาวิทยานิพนธ์การลงทุน","เอกสารการนำเสนอผู้บริหาร","เว็บไซต์และเอกสาร IR","กลยุทธ์สื่อและนักวิเคราะห์"]}]}}}'),
('tr', 'ipo-preparation', '{"ipo_preparation":{"hero":{"title":"Çözümler","title_highlight":"IPO Hazırlığı","description":"Halka açık piyasalara güvenle yönelin.","cta_button_text":"IPO Değerlendirmesi Başlat","cta_button_link":"https://calendly.com/amplifix/amplifix-discovery"},"ipo_process":{"title":"Kapsamlı IPO Hazırlık Platformu","features":[{"title":"S-1 Hazırlığı","description":"AI destekli hazırlık.","icon":"FileText"},{"title":"Uyumluluk Hazırlığı","description":"Kapsamlı SOX hazırlığı.","icon":"Shield"},{"title":"Roadshow Desteği","description":"Yatırımcı sunumu optimizasyonu.","icon":"Users"},{"title":"Zaman Çizelgesi Yönetimi","description":"Detaylı proje yönetimi.","icon":"Clock"},{"title":"Piyasa Konumlandırma","description":"Stratejik anlatı geliştirme.","icon":"TrendingUp"},{"title":"IPO Sonrası Geçiş","description":"Halka açık operasyonlara sorunsuz geçiş.","icon":"CheckCircle"}]},"checklist":{"title":"IPO Hazırlık Kontrol Listesi","sections":[{"section_title":"Finansal ve Hukuki Hazırlık","items":["Denetlenmiş mali tablolar (3 yıl)","SOX uyumluluk uygulaması","Kurumsal yönetim yapısı","Yönetim kurulu kompozisyon optimizasyonu"]},{"section_title":"İletişim ve IR","items":["Yatırım tezi geliştirme","Yönetim sunum materyalleri","IR web sitesi ve materyaller","Medya ve analist stratejisi"]}]}}}'),
('uk', 'ipo-preparation', '{"ipo_preparation":{"hero":{"title":"Рішення","title_highlight":"Підготовка до IPO","description":"Впевнено рухайтеся до публічних ринків.","cta_button_text":"Почати Оцінку IPO","cta_button_link":"https://calendly.com/amplifix/amplifix-discovery"},"ipo_process":{"title":"Комплексна Платформа Готовності до IPO","features":[{"title":"Підготовка S-1","description":"Підготовка за допомогою AI.","icon":"FileText"},{"title":"Готовність до Відповідності","description":"Комплексна підготовка SOX.","icon":"Shield"},{"title":"Підтримка Roadshow","description":"Оптимізація презентацій.","icon":"Users"},{"title":"Управління Часовою Шкалою","description":"Детальне управління проектом.","icon":"Clock"},{"title":"Позиціонування на Ринку","description":"Розвиток стратегічного наративу.","icon":"TrendingUp"},{"title":"Перехід Після IPO","description":"Плавний перехід до публічних операцій.","icon":"CheckCircle"}]},"checklist":{"title":"Контрольний Список Готовності до IPO","sections":[{"section_title":"Фінансова та Юридична Підготовка","items":["Аудійована фінансова звітність (3 роки)","Впровадження відповідності SOX","Структура корпоративного управління","Оптимізація складу ради директорів"]},{"section_title":"Комунікації та IR","items":["Розробка інвестиційної тези","Матеріали для презентації керівництва","Веб-сайт та матеріали IR","Стратегія медіа та аналітиків"]}]}}}')
