('ar', 'syndication', '{"syndication":{"hero":{"title":"التوزيع و","title_highlight":"المشاركة","description":"ضخم رسالتك مع مشاركة المحتوى الذكية عبر شبكات الأخبار المالية والأخبار المتميزة.","cta_button":"استكشف المشاركة"},"key_features":{"title":"شبكة مشاركة قوية","features":[{"title":"شبكة متميزة","description":"توزيع إلى أكثر من 500 موقع أخبار مالية متميز.","icon":"Globe"},{"title":"توزيع مستهدف","description":"الوصول إلى شرائح المستثمرين والمناطق الجغرافية بدقة.","icon":"Target"},{"title":"تحسين SEO","description":"محتوى محسن لمحركات البحث.","icon":"Search"},{"title":"تضخيم اجتماعي","description":"توزيع وسائل التواصل الاجتماعي الآلي.","icon":"Share2"},{"title":"جاهز للامتثال","description":"توزيع متوافق مع SEC.","icon":"Shield"},{"title":"تتبع الأداء","description":"تحليلات في الوقت الفعلي.","icon":"BarChart3"}]},"benefits":{"title":"لماذا مشاركة AmplifiX","items":[{"title":"أقصى وصول","description":"الوصول إلى ملايين المستثمرين."},{"title":"مواضع عالية الجودة","description":"وضع متميز على مواقع الأخبار المالية المحترمة."},{"title":"توزيع فوري","description":"توزيع محتوى في الوقت الفعلي."},{"title":"تقارير شفافة","description":"تقارير مفصلة عن مرات الظهور والتفاعل."}]}}}'),
('ro', 'syndication', '{"syndication":{"hero":{"title":"Distribuție și","title_highlight":"Sindicalizare","description":"Amplifică-ți mesajul cu sindicalizare inteligentă de conținut.","cta_button":"Explorează Sindicalizarea"},"key_features":{"title":"Rețea Puternică de Sindicalizare","features":[{"title":"Rețea Premium","description":"Distribuție la 500+ site-uri de știri financiare.","icon":"Globe"},{"title":"Distribuție Targetată","description":"Atinge segmente de investitori și regiuni.","icon":"Target"},{"title":"Optimizare SEO","description":"Conținut optimizat pentru motoare de căutare.","icon":"Search"},{"title":"Amplificare Socială","description":"Distribuție social media automatizată.","icon":"Share2"},{"title":"Pregătit pentru Conformitate","description":"Distribuție conformă SEC.","icon":"Shield"},{"title":"Urmărire Performanță","description":"Analize în timp real.","icon":"BarChart3"}]},"benefits":{"title":"De Ce Sindicalizarea AmplifiX","items":[{"title":"Acoperire Maximă","description":"Atinge milioane de investitori."},{"title":"Plasări de Calitate","description":"Plasare premium pe site-uri respectate."},{"title":"Distribuție Instantă","description":"Distribuție de conținut în timp real."},{"title":"Raportare Transparentă","description":"Rapoarte detaliate de impresii și engagement."}]}}}'),
('th', 'syndication', '{"syndication":{"hero":{"title":"การกระจายและ","title_highlight":"การเผยแพร่","description":"ขยายข้อความของคุณด้วยการเผยแพร่เนื้อหาอัจฉริยะ","cta_button":"สำรวจการเผยแพร่"},"key_features":{"title":"เครือข่ายการเผยแพร่ที่ทรงพลัง","features":[{"title":"เครือข่ายพรีเมียม","description":"การกระจายไปยังกว่า 500 เว็บไซต์ข่าวการเงิน","icon":"Globe"},{"title":"การกระจายแบบกำหนดเป้าหมาย","description":"เข้าถึงกลุ่มนักลงทุนและภูมิภาค","icon":"Target"},{"title":"การเพิ่มประสิทธิภาพ SEO","description":"เนื้อหาที่ปรับแต่งสำหรับเครื่องมือค้นหา","icon":"Search"},{"title":"การขยายผลทางสังคม","description":"การกระจายโซเชียลมีเดียอัตโนมัติ","icon":"Share2"},{"title":"พร้อมสำหรับการปฏิบัติตาม","description":"การกระจายที่สอดคล้องกับ SEC","icon":"Shield"},{"title":"การติดตามประสิทธิภาพ","description":"การวิเคราะห์แบบเรียลไทม์","icon":"BarChart3"}]},"benefits":{"title":"ทำไมต้องการเผยแพร่ AmplifiX","items":[{"title":"การเข้าถึงสูงสุด","description":"เข้าถึงนักลงทุนหลายล้านคน"},{"title":"การวางตำแหน่งคุณภาพ","description":"การวางตำแหน่งพรีเมียมบนเว็บไซต์ที่น่าเชื่อถือ"},{"title":"การกระจายทันที","description":"การกระจายเนื้อหาแบบเรียลไทม์"},{"title":"รายงานโปร่งใส","description":"รายงานโดยละเอียดเกี่ยวกับการแสดงผลและการมีส่วนร่วม"}]}}}'),
('tr', 'syndication', '{"syndication":{"hero":{"title":"Dağıtım ve","title_highlight":"Sendikasyon","description":"Akıllı içerik sendikasyonu ile mesajınızı güçlendirin.","cta_button":"Sendikasyonu Keşfet"},"key_features":{"title":"Güçlü Sendikasyon Ağı","features":[{"title":"Premium Ağ","description":"500+ premium finans haber sitesine dağıtım.","icon":"Globe"},{"title":"Hedefli Dağıtım","description":"Yatırımcı segmentlerine ve bölgelere ulaşın.","icon":"Target"},{"title":"SEO Optimizasyonu","description":"Arama motorları için optimize edilmiş içerik.","icon":"Search"},{"title":"Sosyal Amplifikasyon","description":"Otomatik sosyal medya dağıtımı.","icon":"Share2"},{"title":"Uyumluluk Hazır","description":"SEC uyumlu dağıtım.","icon":"Shield"},{"title":"Performans İzleme","description":"Gerçek zamanlı analitik.","icon":"BarChart3"}]},"benefits":{"title":"Neden AmplifiX Sendikasyonu","items":[{"title":"Maksimum Erişim","description":"Milyonlarca yatırımcıya ulaşın."},{"title":"Kaliteli Yerleşimler","description":"Saygın sitelerde premium yerleşim."},{"title":"Anında Dağıtım","description":"Gerçek zamanlı içerik dağıtımı."},{"title":"Şeffaf Raporlama","description":"Gösterim ve etkileşim raporları."}]}}}'),
('uk', 'syndication', '{"syndication":{"hero":{"title":"Розповсюдження та","title_highlight":"Синдикація","description":"Посилюйте своє повідомлення за допомогою інтелектуальної синдикації контенту.","cta_button":"Дослідити Синдикацію"},"key_features":{"title":"Потужна Мережа Синдикації","features":[{"title":"Преміум Мережа","description":"Розповсюдження на 500+ преміум фінансових сайтів.","icon":"Globe"},{"title":"Цільове Розповсюдження","description":"Охоплюйте сегменти інвесторів та регіони.","icon":"Target"},{"title":"SEO Оптимізація","description":"Контент оптимізований для пошукових систем.","icon":"Search"},{"title":"Соціальне Посилення","description":"Автоматизоване розповсюдження в соцмережах.","icon":"Share2"},{"title":"Готовність до Відповідності","description":"SEC-відповідне розповсюдження.","icon":"Shield"},{"title":"Відстеження Ефективності","description":"Аналітика в реальному часі.","icon":"BarChart3"}]},"benefits":{"title":"Чому Синдикація AmplifiX","items":[{"title":"Максимальне Охоплення","description":"Охоплюйте мільйони інвесторів."},{"title":"Якісні Розміщення","description":"Преміум розміщення на поважних сайтах."},{"title":"Миттєве Розповсюдження","description":"Розповсюдження контенту в реальному часі."},{"title":"Прозора Звітність","description":"Детальні звіти про покази та залучення."}]}}}')
