('th', 'video-distribution', '{"hero":{"title":"การกระจายวิดีโอ","subtitle":"ขยายแบรนด์ของคุณด้วย Streaming TV และวิดีโอดิจิทัล","description":"สร้างผลลัพธ์ทางธุรกิจที่วัดได้ด้วยการกระจายวิดีโอ AI"},"features":[{"title":"โฆษณา Streaming TV","description":"เข้าถึงผู้ชมใน 500+ ช่องสตรีมมิ่งพรีเมียม","icon":"Tv"},{"title":"การกำหนดเป้าหมายผู้ชม","description":"ไม่มีการแสดงผลที่สูญเปล่า กำหนดเป้าหมายผู้ชมอย่างแม่นยำ","icon":"Target"},{"title":"การเพิ่มประสิทธิภาพ AI","description":"ใช้ประโยชน์จากการเพิ่มประสิทธิภาพแคมเปญด้วย AI","icon":"Brain"},{"title":"โซลูชันสร้างสรรค์","description":"สร้างโฆษณาวิดีโอพร้อมสำหรับทีวี","icon":"Video"},{"title":"การกระจายข้ามแพลตฟอร์ม","description":"กระจายเนื้อหาวิดีโอในทุกอุปกรณ์","icon":"Monitor"},{"title":"การวัดและรายงาน","description":"ติดตามประสิทธิภาพในทุกหน้าจอ","icon":"BarChart3"}],"benefits":[{"title":"สร้างลีด","description":"เปลี่ยนผู้ชมเป็นผู้ซื้อที่มีคุณสมบัติ"},{"title":"เพิ่มยอดขาย","description":"สร้างการเพิ่มยอดขายที่วัดได้"},{"title":"สร้างการรับรู้","description":"อยู่ในใจเสมอ"},{"title":"ดึงดูดทราฟฟิก","description":"ขับเคลื่อนทราฟฟิกที่แปลงได้"}]}'),
